package com.projectbible.post.maven.jpa.postgresql.admin.presentation;
import com.projectbible.post.maven.jpa.postgresql.admin.application.AdminService; import com.projectbible.post.maven.jpa.postgresql.common.api.ApiResponse; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import java.util.Map; import org.springframework.web.bind.annotation.*;
@Tag(name="admin") @RestController @RequestMapping("/api/v1/admin") public class AdminController { private final AdminService service; public AdminController(AdminService service) { this.service=service; } @Operation(summary="Current admin") @GetMapping("/me") public ApiResponse<Map<String,Object>> me() { return ApiResponse.success(service.me()); } @Operation(summary="Admin dashboard") @GetMapping("/dashboard") public ApiResponse<Map<String,Object>> dashboard() { return ApiResponse.success(service.dashboard()); } }
